// core/tree/engine/TreeEvents.ts

/**
 * PrimeReact-compatible event shape.
 * Used across Tree, TreeSelect, TreeTable.
 */
export interface PrimeTreeEvent<T> {
  value: T;
  target: {
    value: T;
  };
  originalEvent?: any;
}

/**
 * Creates a PrimeReact-compatible event.
 */
export function createTreeEvent<T>(
  value: T,
  originalEvent?: any
): PrimeTreeEvent<T> {
  return {
    value,
    target: {
      value,
    },
    originalEvent,
  };
}
